mapper.select:
SELECT T1.ID, T1.MATERIAL_ID, T1.WARNING_THRESHOLD, T1.RECEIVERS, T1.RECEIVER_NAMES, T1.STATUS, DECODE(T1.STATUS, '1', '启用', '0', '禁用', '') AS statusLabel, T1.CREATE_BY, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_TIME, T2.MATERIAL_NAME, T3.CATEGORY_NAME AS MATERIAL_TYPE, T2.SPECIFICATION_MODEL, T2.BRAND, T2.UNIT_NAME, S1.USER_NAME AS createByName FROM E_MATERIAL_WARNING_CONFIG T1 LEFT JOIN E_MATERIAL_CODE T2 ON T1.MATERIAL_ID = T2.ID LEFT JOIN E_MATERIAL_CATEGORY T3 ON T2.CATEGORY_ID = T3.ID LEFT JOIN SYS_USER S1 ON T1.CREATE_BY = S1.ID
1 = 1
AND T2.MATERIAL_NAME LIKE #{materialNamePattern}
AND T1.STATUS = #{status}
AND T2.CATEGORY_ID = #{categoryId}
ORDER BY T1.CREATE_TIME DESC

